use std::collections::BTreeSet;use std::io::{self,Read};fn solve(m:&[Vec<i32>],k:i32)->i32{let(r,c)=(m.len(),m[0].len());let mut best=i32::MIN;for top in 0..r{let mut sums=vec![0;c];for bot in top..r{for j in 0..c{sums[j]+=m[bot][j];}let mut pre=BTreeSet::new();pre.insert(0);let mut cur=0;for x in &sums{cur+=*x;if let Some(&p)=pre.range((cur-k)..).next(){best=best.max(cur-p);}pre.insert(cur);}}}best}fn main(){let mut s=String::new();io::stdin().read_to_string(&mut s).unwrap();let d:Vec<i32>=s.split_whitespace().map(|x|x.parse().unwrap()).collect();if d.is_empty(){return};let mut idx=0;let t=d[idx]as usize;idx+=1;let mut out=Vec::new();for _ in 0..t{let r=d[idx]as usize;let c=d[idx+1]as usize;idx+=2;let mut m=vec![vec![0;c];r];for i in 0..r{for j in 0..c{m[i][j]=d[idx];idx+=1;}}let k=d[idx];idx+=1;out.push(solve(&m,k).to_string());}print!("{}",out.join("\n\n"));}
